233: func newServiceAccountIdentity(key *apikey.APIKey) *authn.Identity {
234: 	return &authn.Identity{
235: 		ID:              strconv.FormatInt(*key.ServiceAccountId, 10),
236: 		Type:            claims.TypeServiceAccount,
237: 		OrgID:           key.OrgID,
238: 		AuthenticatedBy: login.APIKeyAuthModule,
239: 		ClientParams:    authn.ClientParams{FetchSyncedUser: true, SyncPermissions: true},
240: 	}
241: }
242: 
243: func shouldUpdateLastUsedAt(key *apikey.APIKey) bool {
244: 	return key.LastUsedAt == nil || time.Since(*key.LastUsedAt) > 5*time.Minute
245: }
